DECLARE

  table_exists PLS_INTEGER;

BEGIN


  SELECT COUNT(*) INTO table_exists
  FROM "USER_TABLES"
  WHERE TABLE_NAME = 'TEMP_PSP_ENTITLEMENT_CODE';

  IF table_exists = 1 THEN
    EXECUTE IMMEDIATE 'DROP TABLE "TEMP_PSP_ENTITLEMENT_CODE" CASCADE CONSTRAINTS';
  END IF;

END;

/

--------------------------------------------------------
-- Create temp table                                  --
--------------------------------------------------------
CREATE TABLE TEMP_PSP_ENTITLEMENT_CODE
(
  "ENTITLEMENT_CODE_SEQ" VARCHAR2(255 CHAR) NOT NULL,
  "CREATED_DATE" TIMESTAMP NOT NULL,
  "MODIFIED_DATE" TIMESTAMP NOT NULL,
  "EDITION_TYPE" VARCHAR2(255 CHAR),
  "NUMBER_OF_EMPLOYEES_TYPE" VARCHAR2(255 CHAR),
  "QUICK_BOOKS_SUBTYPE" NUMBER(19, 0),
  "SUBTYPE_DESCRIPTION" VARCHAR2(50 CHAR) NOT NULL,
  "ASSET_ITEM_CD" VARCHAR2(255 CHAR),
  "ASSET_ITEM_NUMBER" VARCHAR2(255 CHAR) NOT NULL,
  "IS_PRIMARY" NUMBER(1) NOT NULL,
  "VERSION"  NUMBER(19,0) NOT NULL,
  "IS_USAGE_BILLING" NUMBER(1) NOT NULL,
  "IS_FIRST_USAGE_FREE" NUMBER(1) NOT NULL,
  "BILLING_FREQUENCY_TYPE" VARCHAR2(255 CHAR),
  "ASSET_TYPE_CD" VARCHAR2(255 CHAR)
)

/

